INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, 5, 'primary', m.slot, pos.order_index,
  FALSE, 2, 2, 2, m.impact, 'moderate'
FROM (VALUES
  ('drop-squat-to-stick', 'bilateral_landing_control', 1),
  ('snap-down-to-stick-control-version', 'snapdown_landing_control', 1),
  ('low-box-step-off-to-stick', 'drop_landing_control', 1),
  ('forward-hop-to-stick-low-amplitude', 'forward_landing_control', 1),
  ('lateral-hop-to-stick-low-amplitude', 'lateral_landing_control', 1),
  ('single-leg-hop-to-stick-low-amplitude', 'single_leg_landing_control', 1),
  ('deceleration-step-down-stop-step-stick', 'braking_position_control', 1),
  ('jog-to-stick-linear-deceleration', 'linear_deceleration_control', 1),
  ('lateral-shuffle-to-stick', 'lateral_deceleration_control', 1),
  ('backpedal-to-stick', 'backward_deceleration_control', 1),
  ('single-leg-balance-hold-tripod-foot', 'single_leg_static_balance', 0),
  ('single-leg-balance-reach-clock-control', 'single_leg_reach_control', 0),
  ('y-balance-reach-star-reach', 'multi_direction_reach_control', 0),
  ('single-leg-rdl-reach-bodyweight-control', 'single_leg_hinge_control', 0),
  ('hip-airplane-supported', 'hip_rotation_balance_control', 0),
  ('step-down-to-hover', 'eccentric_stepdown_control', 0),
  ('lateral-step-down', 'frontal_plane_stepdown_control', 0),
  ('single-leg-squat-to-box', 'single_leg_squat_control', 0),
  ('perturbation-single-leg-balance', 'perturbation_balance', 0),
  ('beam-line-balance-freeze', 'narrow_base_balance_control', 0),
  ('dead-bug-heel-tap-control-progression', 'anti_extension_control', 0),
  ('dead-bug-pullover-band-dead-bug', 'loaded_anti_extension_control', 0),
  ('bird-dog-iso-hold', 'contralateral_trunk_control', 0),
  ('front-plank-long-lever-plank', 'anterior_trunk_control', 0),
  ('side-plank', 'lateral_trunk_control', 0),
  ('bear-plank-hold', 'quadruped_trunk_control', 0),
  ('bear-plank-shoulder-tap', 'anti_rotation_quadruped_control', 0),
  ('plank-pull-through', 'dynamic_anti_rotation_control', 0),
  ('pallof-press-iso-hold', 'anti_rotation_hold', 0),
  ('half-kneeling-anti-rotation-press-lift-hold', 'half_kneeling_trunk_control', 0),
  ('quadruped-scapular-push-up-hold', 'scapular_quadruped_control', 0),
  ('prone-y-t-w-isometric-series', 'scapular_posterior_chain_control', 0),
  ('tall-plank-shoulder-tap', 'plank_shoulder_control', 0),
  ('slow-bear-crawl', 'crawling_control', 0),
  ('crab-reverse-tabletop-hold', 'posterior_support_control', 0),
  ('wall-handstand-line-hold', 'handstand_line_control', 0),
  ('wall-handstand-shoulder-shrug', 'overhead_scapular_control', 0),
  ('wall-walk-negative-controlled-wall-walk-down', 'handstand_eccentric_control', 0),
  ('ring-support-hold-assisted-control', 'straight_arm_support_control', 0),
  ('wrist-lean-isometric-wrist-support-rock-hold', 'wrist_support_control', 0),
  ('split-squat-eccentric-to-pause', 'split_stance_eccentric_control', 0),
  ('isometric-lateral-lunge-hold', 'frontal_plane_isometric_control', 0),
  ('cossack-bottom-hold-cossack-shift-hold', 'deep_frontal_plane_control', 0),
  ('adductor-squeeze-bridge-hold', 'adductor_isometric_control', 0),
  ('hamstring-bridge-iso-long-lever-bridge-hold', 'hamstring_bridge_control', 0),
  ('slider-hamstring-eccentric-slow-lower', 'hamstring_eccentric_control', 0),
  ('calf-isometric-hold-straight-knee', 'gastroc_isometric_control', 0),
  ('soleus-isometric-hold-bent-knee', 'soleus_isometric_control', 0),
  ('tibialis-iso-toe-up-hold', 'tibialis_isometric_control', 0),
  ('nordic-lean-isometric-partial-range', 'hamstring_isometric_resilience', 0)
) AS m(slug, slot, impact)
JOIN coaching.exercise e ON e.slug = m.slug
JOIN coaching.session_phase sp ON sp.key = 'control_resilience'
JOIN coaching.phase_order_slot pos ON pos.key = m.slot AND pos.phase_id = sp.id
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role, order_slot = EXCLUDED.order_slot, fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required, fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  impact_level = EXCLUDED.impact_level, intensity_ceiling = EXCLUDED.intensity_ceiling;

INSERT INTO coaching.exercise_dosage_profile (
  exercise_id, profile_name, is_default, volume_unit, default_sets, default_reps,
  default_work_seconds, default_rest_seconds, default_distance, est_seconds_per_set, default_rpe_min, default_rpe_max
)
SELECT e.id, 'Default', TRUE, m.unit, m.sets, m.reps, m.work, m.rest, m.distance, m.est, 4, 7
FROM (VALUES
