INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary, what_it_is, why_it_matters,
  why_it_goes_here, programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name,
  e.card_summary,
  COALESCE(e.description, e.name),
  'Teaches the athlete to organize force safely through position ownership, alignment, and low-speed resilience.',
  CASE e.phase_subrole
    WHEN 'landing_braking_control' THEN 'Belongs in Landing & Braking Control — absorb force, stick landings, and organize knee/hip/ankle alignment.'
    WHEN 'single_leg_balance_foot_ankle_hip_control' THEN 'Belongs in Single-Leg Balance / Foot-Ankle-Hip Control — stance quality, foot tripod, and hip/pelvis ownership.'
    WHEN 'trunk_pelvis_anti_movement_control' THEN 'Belongs in Trunk / Pelvis / Anti-Movement Control — anti-extension, anti-rotation, and rib/pelvis stiffness.'
    WHEN 'scapular_wrist_hand_support_resilience' THEN 'Belongs in Scapular / Wrist / Hand-Support Resilience — shoulder-blade, wrist, and hand-support durability.'
    WHEN 'slow_eccentric_isometric_joint_resilience' THEN 'Belongs in Slow Eccentric / Isometric Joint Resilience — low-speed joint and tissue tolerance through holds and slow eccentrics.'
    ELSE 'Place in Control / Resilience after Output and usually after Capacity — precision before Fitness fatigue.'
  END,
  'Use holds, slow eccentrics, and sticks with full rest. Progress via longer holds, slower tempo, smaller base, or perturbation — not random burnout.',
  'Do not use short-rest high-density circuits and call it Control. Hard resilience work is not daily max-intensity tissue loading.',
  'Youth: supervision on perturbation, handstand, and landing progressions. Scale by alignment quality first.'
FROM coaching.exercise e
WHERE e.slug IN ('drop-squat-to-stick', 'snap-down-to-stick-control-version', 'low-box-step-off-to-stick', 'forward-hop-to-stick-low-amplitude', 'lateral-hop-to-stick-low-amplitude', 'single-leg-hop-to-stick-low-amplitude', 'deceleration-step-down-stop-step-stick', 'jog-to-stick-linear-deceleration', 'lateral-shuffle-to-stick', 'backpedal-to-stick', 'single-leg-balance-hold-tripod-foot', 'single-leg-balance-reach-clock-control', 'y-balance-reach-star-reach', 'single-leg-rdl-reach-bodyweight-control', 'hip-airplane-supported', 'step-down-to-hover', 'lateral-step-down', 'single-leg-squat-to-box', 'perturbation-single-leg-balance', 'beam-line-balance-freeze', 'dead-bug-heel-tap-control-progression', 'dead-bug-pullover-band-dead-bug', 'bird-dog-iso-hold', 'front-plank-long-lever-plank', 'side-plank', 'bear-plank-hold', 'bear-plank-shoulder-tap', 'plank-pull-through', 'pallof-press-iso-hold', 'half-kneeling-anti-rotation-press-lift-hold', 'quadruped-scapular-push-up-hold', 'prone-y-t-w-isometric-series', 'tall-plank-shoulder-tap', 'slow-bear-crawl', 'crab-reverse-tabletop-hold', 'wall-handstand-line-hold', 'wall-handstand-shoulder-shrug', 'wall-walk-negative-controlled-wall-walk-down', 'ring-support-hold-assisted-control', 'wrist-lean-isometric-wrist-support-rock-hold', 'split-squat-eccentric-to-pause', 'isometric-lateral-lunge-hold', 'cossack-bottom-hold-cossack-shift-hold', 'adductor-squeeze-bridge-hold', 'hamstring-bridge-iso-long-lever-bridge-hold', 'slider-hamstring-eccentric-slow-lower', 'calf-isometric-hold-straight-knee', 'soleus-isometric-hold-bent-knee', 'tibialis-iso-toe-up-hold', 'nordic-lean-isometric-partial-range')
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

